# ANTI-PATTERN: Loading full model for every inference request
class CricketCommentaryBot_Bad:
    def generate_comment(self, bowler_name, runs_scored):
        # Reloading 7B parameter model (35GB) on each call
        model = load_full_model('llama-7b')  # 8 seconds
        prompt = f"{bowler_name} just conceded {runs_scored} runs"
        return model.generate(prompt)

bat_performance = CricketCommentaryBot_Bad()
commentary = bat_performance.generate_comment("Bumrah", 4)  # 8 seconds latency

# BEST PRACTICE: Quantized model with batch processing
class CricketCommentaryBot_Good:
    def __init__(self):
        # Load once: 7B model quantized to INT8 (9GB, loads in 1 second)
        self.model = load_quantized_model('llama-7b-int8')
        self.request_queue = []
        self.batch_size = 32

    def queue_commentary(self, bowler_name, runs_scored):
        request = {"bowler": bowler_name, "runs": runs_scored}
        self.request_queue.append(request)
        if len(self.request_queue) >= self.batch_size:
            return self.process_batch()

    def process_batch(self):
        # Vectorized batch inference: 32 requests in 0.5 seconds
        prompts = [f"{r['bowler']} conceded {r['runs']} runs" 
                   for r in self.request_queue]
        results = self.model.generate_batch(prompts)
        self.request_queue.clear()
        return results

bot = CricketCommentaryBot_Good()
bot.queue_commentary("Bumrah", 4)      # <1ms queue time
bot.queue_commentary("Siraj", 6)       # <1ms queue time
commentaries = bot.process_batch()     # 500ms for 32 requests (15.6ms per request)
